const { open } = require('node:fs/promises');
const path = require('node:path');
const { pathToFileURL } = require('node:url');

const baseInputs = Array.from(new Set([
  process.env.CLAUDE_PLUGIN_ROOT,
  process.env.CODEX_PLUGIN_ROOT,
  process.env.PLUGIN_ROOT,
  process.env.INIT_CWD,
  process.env.PWD,
  process.cwd()
].filter(Boolean)));

function walkUp(startDir, maxParents) {
  const dirs = [];
  let dir = path.resolve(startDir);
  for (let i = 0; i < maxParents; i++) {
    dirs.push(dir);
    const parent = path.dirname(dir);
    if (parent === dir) {
      break;
    }
    dir = parent;
  }
  return dirs;
}

async function readPrefix(filePath, maxBytes) {
  const handle = await open(filePath, 'r');
  try {
    const buffer = Buffer.alloc(maxBytes);
    const result = await handle.read(buffer, 0, maxBytes, 0);
    return buffer.subarray(0, result.bytesRead).toString('utf8');
  } finally {
    await handle.close();
  }
}

(async () => {
  const searchDirs = [];
  for (const input of baseInputs) {
    for (const dir of walkUp(input, 10)) {
      searchDirs.push(dir);
    }
  }

  const dedupedSearchDirs = Array.from(new Set(searchDirs));

  const candidates = [];
  for (const root of dedupedSearchDirs) {
    candidates.push(path.join(root, 'runtime', 'dist', 'server.js'));
    candidates.push(path.join(root, 'plugins', 'claude-interrogate', 'runtime', 'dist', 'server.js'));
  }

  let serverPath;
  for (const candidate of candidates) {
    try {
      const prefix = await readPrefix(candidate, 4096);
      if (!prefix.includes('claude-interrogate MCP server')) {
        continue;
      }
      serverPath = candidate;
      break;
    } catch {
      // continue
    }
  }

  if (!serverPath) {
    const checked = candidates.slice(0, 24).join(', ') + (candidates.length > 24 ? ', ... (' + candidates.length + ' total)' : '');
    throw new Error(
      [
        'Could not locate claude-interrogate runtime/dist/server.js',
        'cwd: ' + process.cwd(),
        'baseInputs: ' + baseInputs.join(', '),
        'checked: ' + checked
      ].join('\n')
    );
  }

  process.argv[1] = serverPath;
  await import(pathToFileURL(serverPath).href);
})().catch((error) => {
  console.error(error instanceof Error ? error.stack || error.message : String(error));
  process.exit(1);
});
